module mux2to1_16bit (
    input sel,
    input [15:0] in0,
    input [15:0] in1,
    output [15:0] out
);

    reg [15:0] invalid_mux;  // Multiplexer output register

    always @(*) begin
        case (sel)
            1'b0: invalid_mux = in0;
            1'b1: invalid_mux = in1;
            default: invalid_mux = 16'b0;  // Default case (should not occur)
        endcase
    end

    assign out = invalid_mux;

endmodule
